"use client";
import{useState,useEffect,useCallback,useRef}from"react";
import{createClient}from"@/shared/supabase/client";
import{STATUSES,REPAIR_STATUSES,DELIVERY_VISIBLE_FROM,ALL_STATUS_COLORS,PAY_COLORS,CATEGORIES,FINISH_TYPES,WOOD_TYPES,REPAIR_REASONS,CUSTOMER_TYPES,PAYMENT_TERMS,DOC_TYPES,DOC_ICONS,ROLES_CAN_CREATE,ROLES_CAN_EDIT,ROLES_CAN_ADVANCE,ROLES_CAN_ADD_NOTES,ROLES_CAN_UPLOAD,ROLES_CAN_DELIVER,ROLES_CAN_PAY,ROLES_CAN_REPAIR,SALES_MAX_ADVANCE_TO,STATUS_BORDER_CLASS,ss,getPayStatus,getStatusList,genId}from"./constants";

async function logAct(sb,oid,t,d,o,n){await sb.from("order_activities").insert({order_id:oid,activity_type:t,description:d,old_value:o||null,new_value:n||null})}
function Badge({status,type}){const c=(type==="payment"?PAY_COLORS:ALL_STATUS_COLORS)[status]||{bg:"#eee",text:"#333",border:"#ccc"};return <span style={{display:"inline-block",padding:"3px 8px",borderRadius:"4px",fontSize:"10px",fontWeight:700,letterSpacing:"0.3px",textTransform:"uppercase",background:c.bg,color:c.text,border:`1.5px solid ${c.border}`}}>{status}</span>}
function TruncText({text,lines}){const[exp,setExp]=useState(false);if(!text)return null;const st=exp?{}:{display:"-webkit-box",WebkitLineClamp:lines||3,WebkitBoxOrient:"vertical",overflow:"hidden"};return <div><div style={{...st,fontSize:"13px",color:"#333",whiteSpace:"pre-wrap",lineHeight:1.5}}>{text}</div>{text.length>150&&<button onClick={()=>setExp(!exp)} style={{background:"none",border:"none",color:"#1565C0",cursor:"pointer",fontSize:"11px",fontWeight:600,padding:"4px 0"}}>{exp?"Show less":"Show more"}</button>}</div>}

/* === ITEMS BUILDER === */
function ItemsBuilder({items,onChange}){
  const add=()=>onChange([{_id:genId(),category:"Wall Decoration Canvas",description:"",quantity:1,size:"",finish_type:"None",finish_color:"",wood_type:"",unit_price:"",notes:""},...items]);
  const upd=(id,f,v)=>onChange(items.map(i=>i._id===id?{...i,[f]:v}:i));const del=(id)=>onChange(items.filter(i=>i._id!==id));
  return(<div style={{marginTop:"4px"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"8px"}}><div style={ss.label}>Order Items</div><button type="button" onClick={add} style={{...ss.btn,background:"#1a1a1a",color:"#fff",fontSize:"12px",padding:"6px 14px"}}>+ Add Item</button></div>
    {items.length===0&&<div style={{fontSize:"12px",color:"#bbb",padding:"16px",textAlign:"center",background:"#fafafa",borderRadius:"6px",border:"1px dashed #ddd"}}>No items yet.</div>}
    {items.map((item,idx)=>(<div key={item._id} style={{background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0",padding:"12px",marginBottom:"8px"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"8px"}}><span style={{fontSize:"12px",fontWeight:700,color:"#999"}}>Item {idx+1}</span><button type="button" onClick={()=>del(item._id)} style={{background:"none",border:"none",color:"#C62828",cursor:"pointer",fontSize:"12px",fontWeight:700}}>Remove</button></div>
      <div className="form-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:"8px"}}><div><label style={{...ss.label,fontSize:"10px"}}>Category</label><select value={item.category} onChange={e=>upd(item._id,"category",e.target.value)} style={ss.sm}>{CATEGORIES.map(c=><option key={c}>{c}</option>)}</select></div><div><label style={{...ss.label,fontSize:"10px"}}>Qty</label><input type="number" value={item.quantity} onChange={e=>upd(item._id,"quantity",parseInt(e.target.value)||1)} style={ss.sm} min="1"/></div><div><label style={{...ss.label,fontSize:"10px"}}>Size</label><input type="text" value={item.size} onChange={e=>upd(item._id,"size",e.target.value)} placeholder="e.g. 60x40cm" style={ss.sm}/></div><div><label style={{...ss.label,fontSize:"10px"}}>Finish Type</label><select value={item.finish_type} onChange={e=>upd(item._id,"finish_type",e.target.value)} style={ss.sm}>{FINISH_TYPES.map(f=><option key={f}>{f}</option>)}</select></div><div><label style={{...ss.label,fontSize:"10px"}}>Finish Color</label><input type="text" value={item.finish_color} onChange={e=>upd(item._id,"finish_color",e.target.value)} placeholder="e.g. Dark Walnut" style={ss.sm}/></div><div><label style={{...ss.label,fontSize:"10px"}}>Wood Type</label><select value={item.wood_type} onChange={e=>upd(item._id,"wood_type",e.target.value)} style={ss.sm}><option value="">-</option>{WOOD_TYPES.map(w=><option key={w}>{w}</option>)}</select></div><div><label style={{...ss.label,fontSize:"10px"}}>Unit Price (KES)</label><input type="number" value={item.unit_price} onChange={e=>upd(item._id,"unit_price",e.target.value)} style={ss.sm}/></div><div style={{gridColumn:"1 / -1"}}><label style={{...ss.label,fontSize:"10px"}}>Description</label><input type="text" value={item.description||""} onChange={e=>upd(item._id,"description",e.target.value)} placeholder="Details" style={ss.sm}/></div></div></div>))}</div>);
}

/* === ITEMS TABLE === */
function ItemsTable({items}){if(!items||items.length===0)return null;const total=items.reduce((s,i)=>(parseFloat(i.unit_price)||0)*(i.quantity||1)+s,0);
  return(<div style={{marginTop:"14px"}}><div style={ss.label}>Items ({items.length})</div>
    <div className="items-table" style={{overflowX:"auto",marginTop:"6px"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:"12px"}}><thead><tr style={{background:"#f5f5f3",textAlign:"left"}}>{["#","Category","Description","Qty","Size","Finish","Wood","Price"].map(h=><th key={h} style={{padding:"6px 8px",fontWeight:600,color:"#888",fontSize:"10px",textTransform:"uppercase",borderBottom:"1px solid #eee",whiteSpace:"nowrap"}}>{h}</th>)}</tr></thead><tbody>{items.map((item,i)=><tr key={item.id||i} style={{borderBottom:"1px solid #f0f0f0"}}><td style={{padding:"6px 8px",color:"#bbb"}}>{i+1}</td><td style={{padding:"6px 8px",fontWeight:600,whiteSpace:"nowrap"}}>{item.category}</td><td style={{padding:"6px 8px",color:"#666",maxWidth:"200px"}}>{item.description||"-"}</td><td style={{padding:"6px 8px",fontWeight:700}}>{item.quantity}</td><td style={{padding:"6px 8px",whiteSpace:"nowrap"}}>{item.size||"-"}</td><td style={{padding:"6px 8px",whiteSpace:"nowrap"}}>{item.finish_type&&item.finish_type!=="None"?<>{item.finish_type}{item.finish_color&&<span style={{color:"#888"}}> - {item.finish_color}</span>}</>:"-"}</td><td style={{padding:"6px 8px",whiteSpace:"nowrap"}}>{item.wood_type||"-"}</td><td style={{padding:"6px 8px",fontWeight:600}}>{parseFloat(item.unit_price)?`KES ${((parseFloat(item.unit_price))*(item.quantity||1)).toLocaleString()}`:"-"}</td></tr>)}</tbody>{total>0&&<tfoot><tr style={{background:"#f5f5f3"}}><td colSpan={7} style={{padding:"6px 8px",fontWeight:700,textAlign:"right",fontSize:"11px"}}>TOTAL</td><td style={{padding:"6px 8px",fontWeight:700}}>KES {total.toLocaleString()}</td></tr></tfoot>}</table></div>
    <div className="items-cards" style={{display:"none",flexDirection:"column",gap:"8px",marginTop:"6px"}}>{items.map((item,i)=><div key={item.id||i} style={{background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0",padding:"12px"}}><div style={{fontSize:"13px",fontWeight:700,marginBottom:"4px"}}>{item.category}</div>{item.description&&<div style={{fontSize:"12px",color:"#666",marginBottom:"6px"}}>{item.description}</div>}<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px",fontSize:"11px"}}><div><span style={{color:"#888"}}>Qty:</span> <strong>{item.quantity}</strong></div>{item.size&&<div><span style={{color:"#888"}}>Size:</span> {item.size}</div>}{item.finish_type&&item.finish_type!=="None"&&<div><span style={{color:"#888"}}>Finish:</span> {item.finish_type}{item.finish_color?" - "+item.finish_color:""}</div>}{item.wood_type&&<div><span style={{color:"#888"}}>Wood:</span> {item.wood_type}</div>}{parseFloat(item.unit_price)>0&&<div><span style={{color:"#888"}}>Price:</span> <strong>KES {((parseFloat(item.unit_price))*(item.quantity||1)).toLocaleString()}</strong></div>}</div></div>)}{total>0&&<div style={{textAlign:"right",fontSize:"12px",fontWeight:700,padding:"4px 0"}}>Total: KES {total.toLocaleString()}</div>}</div>
  </div>);
}

/* === NOTES === */
function NotesThread({orderId,userRole,userName,orderStatus}){const[notes,setNotes]=useState([]);const[text,setText]=useState("");const[ld,setLd]=useState(true);const sb=createClient();
  const load=useCallback(async()=>{const{data}=await sb.from("order_notes").select("*").eq("order_id",orderId).order("created_at",{ascending:false});setNotes(data||[]);setLd(false)},[orderId]);useEffect(()=>{load()},[load]);
  const add=async()=>{if(!text.trim())return;await sb.from("order_notes").insert({order_id:orderId,content:text.trim(),author_name:userName||"Unknown"});await logAct(sb,orderId,"note",`Note: ${text.trim().slice(0,80)}`);setText("");await load()};
  return(<div style={{marginTop:"18px",padding:"16px",background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0"}}><div style={{...ss.label,marginBottom:"12px",color:"#666"}}>Notes</div>
    {ROLES_CAN_ADD_NOTES.includes(userRole)&&orderStatus!=="Closed"&&<div style={{display:"flex",gap:"8px",marginBottom:"12px"}}><input type="text" value={text} onChange={e=>setText(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")add()}} placeholder="Add a note..." style={{...ss.sm,flex:1}}/><button onClick={add} disabled={!text.trim()} style={{...ss.btn,background:text.trim()?"#1a1a1a":"#ccc",color:"#fff",fontSize:"12px",padding:"6px 14px"}}>Post</button></div>}
    {ld?<div style={{fontSize:"12px",color:"#bbb"}}>Loading...</div>:notes.length===0?<div style={{fontSize:"12px",color:"#bbb",fontStyle:"italic"}}>No notes yet.</div>:<div style={{display:"flex",flexDirection:"column",gap:"6px",maxHeight:"250px",overflowY:"auto"}}>{notes.map(n=><div key={n.id} style={{padding:"8px 10px",background:"#fff",borderRadius:"6px",border:"1px solid #e8e8e5"}}><div style={{fontSize:"13px",color:"#333",whiteSpace:"pre-wrap"}}>{n.content}</div><div style={{fontSize:"10px",color:"#bbb",marginTop:"4px"}}>{n.author_name} - {new Date(n.created_at).toLocaleDateString("en-GB",{day:"numeric",month:"short"})} {new Date(n.created_at).toLocaleTimeString("en-GB",{hour:"2-digit",minute:"2-digit"})}</div></div>)}</div>}</div>);
}

/* === DELIVERY === */
function DeliveryPanel({orderId,totalQty,userRole,payBalance,onDeliveryChange,orderStatus,onAutoAdvance}){
  const[batches,setBatches]=useState([]);const[ld,setLd]=useState(true);const[showForm,setShowForm]=useState(false);const[editId,setEditId]=useState(null);
  const[qty,setQty]=useState("");const[desc,setDesc]=useState("");const[loc,setLoc]=useState("");const[delBy,setDelBy]=useState("");const[recBy,setRecBy]=useState("");const[notes,setNotes]=useState("");const[authReason,setAuthReason]=useState("");
  const sb=createClient();const load=useCallback(async()=>{const{data}=await sb.from("order_deliveries").select("*").eq("order_id",orderId).order("batch_number");setBatches(data||[]);setLd(false);const t=(data||[]).reduce((s,b)=>s+(b.quantity||0),0);if(onDeliveryChange)onDeliveryChange(t)},[orderId]);
  useEffect(()=>{load()},[load]);
  const delivered=batches.reduce((s,b)=>s+(b.quantity||0),0);const remaining=Math.max((totalQty||0)-delivered,0);const pct=totalQty>0?Math.round((delivered/totalQty)*100):0;
  const needsAuth=payBalance>0;const isAdmin=userRole==="admin";const canDeliver=ROLES_CAN_DELIVER.includes(userRole);const isClosed=orderStatus==="Closed";
  const resetForm=()=>{setQty("");setDesc("");setLoc("");setDelBy("");setRecBy("");setNotes("");setAuthReason("");setShowForm(false);setEditId(null)};
  const startEdit=(b)=>{setEditId(b.id);setQty(String(b.quantity));setDesc(b.description||"");setLoc(b.delivery_location||"");setDelBy(b.delivered_by||"");setRecBy(b.received_by||"");setNotes(b.notes||"");setShowForm(true)};
  const record=async()=>{const q=parseInt(qty);if(!q||q<=0)return;const existingDel=editId?delivered-((batches.find(b=>b.id===editId)?.quantity)||0):delivered;if(totalQty>0&&(existingDel+q)>totalQty){alert(`Delivery exceeds remaining units.\nTotal: ${totalQty}\nDelivered: ${existingDel}\nRemaining: ${totalQty-existingDel}\nEntered: ${q}`);return}
    if(editId){await sb.from("order_deliveries").update({quantity:q,description:desc.trim()||null,delivery_location:loc.trim()||null,delivered_by:delBy.trim()||null,received_by:recBy.trim()||null,notes:notes.trim()||null}).eq("id",editId);await logAct(sb,orderId,"delivery_edited",`Batch edited: ${q} units${loc?" to "+loc:""}`)}
    else{const bn=(batches.length>0?Math.max(...batches.map(b=>b.batch_number)):0)+1;await sb.from("order_deliveries").insert({order_id:orderId,batch_number:bn,quantity:q,description:desc.trim()||null,delivery_location:loc.trim()||null,delivered_by:delBy.trim()||null,received_by:recBy.trim()||null,notes:notes.trim()||null,admin_authorized:needsAuth&&isAdmin,admin_auth_reason:needsAuth?authReason.trim()||null:null,payment_status_at_delivery:payBalance>0?"Balance pending":"Paid"});await logAct(sb,orderId,"delivery",`Batch ${bn}: ${q} units${loc?" to "+loc:""}${needsAuth?" [Admin auth]":""}`)}
    resetForm();await load();if(orderStatus==="Ready for Delivery"&&onAutoAdvance&&!editId){onAutoAdvance("Partially Delivered")}};
  return(<div style={{marginTop:"18px",padding:"16px",background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"12px"}}><div style={{...ss.label,marginBottom:0,color:"#666"}}>Delivery Tracking</div>{canDeliver&&!isClosed&&<button onClick={()=>{if(showForm)resetForm();else setShowForm(true)}} style={{...ss.btn,background:"#1a1a1a",color:"#fff",fontSize:"11px",padding:"5px 12px"}}>{showForm?"Cancel":"+ Record Batch"}</button>}</div>
    {totalQty>0&&<div style={{marginBottom:"14px"}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:"8px",marginBottom:"8px",fontSize:"12px"}}><div style={{background:"#f5f5f3",borderRadius:"6px",padding:"8px 10px"}}><div style={{color:"#888",fontSize:"10px",fontWeight:600}}>TOTAL</div><div style={{fontWeight:700}}>{totalQty}</div></div><div style={{background:"#E8F5E9",borderRadius:"6px",padding:"8px 10px"}}><div style={{color:"#2E7D32",fontSize:"10px",fontWeight:600}}>DELIVERED</div><div style={{fontWeight:700,color:"#2E7D32"}}>{delivered}</div></div><div style={{background:remaining>0?"#FFF3E0":"#f5f5f3",borderRadius:"6px",padding:"8px 10px"}}><div style={{color:remaining>0?"#E65100":"#888",fontSize:"10px",fontWeight:600}}>REMAINING</div><div style={{fontWeight:700,color:remaining>0?"#E65100":"#999"}}>{remaining}</div></div><div style={{background:pct>=100?"#E8F5E9":"#E3F2FD",borderRadius:"6px",padding:"8px 10px"}}><div style={{color:pct>=100?"#2E7D32":"#1565C0",fontSize:"10px",fontWeight:600}}>PROGRESS</div><div style={{fontWeight:700,color:pct>=100?"#2E7D32":"#1565C0"}}>{pct}%</div></div></div><div style={{height:"8px",background:"#eee",borderRadius:"4px",overflow:"hidden"}}><div style={{height:"100%",width:`${Math.min(pct,100)}%`,background:pct>=100?"#2E7D32":"#1565C0",borderRadius:"4px"}}/></div></div>}
    {!ld&&batches.length>0&&<div style={{display:"flex",flexDirection:"column",gap:"4px",marginBottom:"12px"}}>{batches.map(b=><div key={b.id} style={{padding:"8px 10px",background:"#fff",borderRadius:"6px",border:"1px solid #e8e8e5",fontSize:"12px"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"2px"}}><span style={{fontWeight:700}}>Batch {b.batch_number} - {b.quantity} units</span><div style={{display:"flex",gap:"6px",alignItems:"center"}}><span style={{color:"#999",fontSize:"11px"}}>{new Date(b.delivery_date).toLocaleDateString("en-GB",{day:"numeric",month:"short"})}</span>{canDeliver&&!isClosed&&<button onClick={()=>startEdit(b)} style={{background:"none",border:"1px solid #ddd",borderRadius:"4px",padding:"2px 6px",fontSize:"10px",color:"#1565C0",cursor:"pointer",fontWeight:600}}>Edit</button>}</div></div>{b.delivery_location&&<div style={{color:"#666"}}>{b.delivery_location}</div>}{b.description&&<div style={{color:"#666"}}>{b.description}</div>}{b.admin_authorized&&<div style={{fontSize:"10px",color:"#E65100",marginTop:"2px"}}>Admin authorized{b.admin_auth_reason?`: ${b.admin_auth_reason}`:""}</div>}</div>)}</div>}
    {showForm&&<div style={{background:"#fff",borderRadius:"8px",border:"1px solid #e0e0e0",padding:"14px",marginTop:"8px"}}>{needsAuth&&!isAdmin&&<div style={{padding:"10px",background:"#FCE4EC",borderRadius:"6px",marginBottom:"12px",fontSize:"12px",color:"#C62828",fontWeight:600}}>Outstanding balance. Contact Admin to authorize.</div>}
      {(canDeliver&&(!needsAuth||isAdmin))&&<div className="form-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"8px"}}><div><label style={{...ss.label,fontSize:"10px"}}>Quantity *</label><input type="number" value={qty} onChange={e=>setQty(e.target.value)} style={ss.sm} min="1"/></div><div><label style={{...ss.label,fontSize:"10px"}}>Location</label><input type="text" value={loc} onChange={e=>setLoc(e.target.value)} placeholder="Block A" style={ss.sm}/></div><div><label style={{...ss.label,fontSize:"10px"}}>Delivered By</label><input type="text" value={delBy} onChange={e=>setDelBy(e.target.value)} style={ss.sm}/></div><div><label style={{...ss.label,fontSize:"10px"}}>Received By</label><input type="text" value={recBy} onChange={e=>setRecBy(e.target.value)} style={ss.sm}/></div><div style={{gridColumn:"1 / -1"}}><label style={{...ss.label,fontSize:"10px"}}>Description</label><input type="text" value={desc} onChange={e=>setDesc(e.target.value)} style={ss.sm}/></div>{needsAuth&&isAdmin&&<div style={{gridColumn:"1 / -1"}}><label style={{...ss.label,fontSize:"10px",color:"#E65100"}}>Authorization Reason *</label><input type="text" value={authReason} onChange={e=>setAuthReason(e.target.value)} placeholder="Reason for delivery with balance" style={ss.sm}/></div>}<div style={{gridColumn:"1 / -1"}}><button onClick={record} disabled={!parseInt(qty)||(needsAuth&&isAdmin&&!authReason.trim()&&!editId)} style={{...ss.btn,background:parseInt(qty)?"#2E7D32":"#ccc",color:"#fff",fontSize:"12px",padding:"8px 16px"}}>{editId?"Update Batch":"Record Delivery"}</button></div></div>}</div>}
  </div>);
}

/* === PAYMENTS === */
function PaymentPanel({orderId,totalValue,userRole,onPaymentChange,orderStatus}){const[payments,setPayments]=useState([]);const[ld,setLd]=useState(true);const[amt,setAmt]=useState("");const[desc,setDesc]=useState("");const[payDate,setPayDate]=useState(new Date().toISOString().split("T")[0]);const sb=createClient();
  const load=useCallback(async()=>{const{data}=await sb.from("order_payments").select("*").eq("order_id",orderId).order("payment_date");const l=data||[];setPayments(l);setLd(false);if(onPaymentChange)onPaymentChange(l.reduce((s,p)=>s+(parseFloat(p.amount)||0),0))},[orderId]);useEffect(()=>{load()},[load]);
  const add=async()=>{const a=parseFloat(amt);if(!a||a<=0||!desc.trim())return;await sb.from("order_payments").insert({order_id:orderId,amount:a,description:desc.trim(),payment_date:payDate});await logAct(sb,orderId,"payment",`Payment: KES ${a.toLocaleString()} - ${desc.trim()}`);setAmt("");setDesc("");setPayDate(new Date().toISOString().split("T")[0]);await load()};
  const del=async(p)=>{await sb.from("order_payments").delete().eq("id",p.id);await logAct(sb,orderId,"payment_deleted",`Removed: KES ${parseFloat(p.amount).toLocaleString()}`);await load()};
  const tp=payments.reduce((s,p)=>s+(parseFloat(p.amount)||0),0);const bal=(totalValue||0)-tp;const pct=totalValue>0?Math.round((tp/totalValue)*100):0;const ps=getPayStatus(tp,totalValue);const canPay=ROLES_CAN_PAY.includes(userRole);
  return(<div style={{marginTop:"18px",padding:"16px",background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"12px"}}><div style={{...ss.label,marginBottom:0,color:"#666"}}>Payments</div><Badge status={ps} type="payment"/></div>
    {totalValue>0&&<div style={{marginBottom:"14px"}}><div style={{display:"flex",justifyContent:"space-between",fontSize:"12px",color:"#666",marginBottom:"6px"}}><span>KES {tp.toLocaleString()} of KES {totalValue.toLocaleString()}</span><span style={{fontWeight:700,color:pct>=100?"#2E7D32":pct>=50?"#1565C0":"#C62828"}}>{pct}%</span></div><div style={{height:"8px",background:"#eee",borderRadius:"4px",overflow:"hidden"}}><div style={{height:"100%",width:`${Math.min(pct,100)}%`,background:pct>=100?"#2E7D32":pct>=50?"#1565C0":"#E65100",borderRadius:"4px"}}/></div><div style={{display:"flex",justifyContent:"space-between",fontSize:"11px",color:"#999",marginTop:"4px"}}><span>Paid: KES {tp.toLocaleString()}</span><span>Balance: KES {Math.max(bal,0).toLocaleString()}</span></div></div>}
    {!ld&&payments.length>0&&<div style={{display:"flex",flexDirection:"column",gap:"4px",marginBottom:"12px"}}>{payments.map(p=><div key={p.id} style={{display:"flex",alignItems:"center",gap:"8px",padding:"6px 10px",background:"#fff",borderRadius:"6px",border:"1px solid #e8e8e5",fontSize:"12px",flexWrap:"wrap"}}><span style={{fontWeight:700,color:"#2E7D32",minWidth:"90px"}}>KES {parseFloat(p.amount).toLocaleString()}</span><span style={{flex:1,color:"#666",minWidth:"80px"}}>{p.description}</span><span style={{color:"#bbb",fontSize:"11px"}}>{new Date(p.payment_date).toLocaleDateString("en-GB",{day:"numeric",month:"short"})}</span>{userRole==="admin"&&<button onClick={()=>{if(confirm("Delete?"))del(p)}} style={{background:"none",border:"none",color:"#C62828",cursor:"pointer",fontSize:"12px",fontWeight:700}}>x</button>}</div>)}</div>}
    {canPay&&orderStatus!=="Closed"&&<div style={{display:"flex",gap:"8px",flexWrap:"wrap",alignItems:"center"}}><input type="number" placeholder="Amount" value={amt} onChange={e=>setAmt(e.target.value)} style={{...ss.sm,maxWidth:"110px"}}/><input type="text" placeholder="Description" value={desc} onChange={e=>setDesc(e.target.value)} style={{...ss.sm,flex:1,minWidth:"80px"}}/><input type="date" value={payDate} onChange={e=>setPayDate(e.target.value)} style={{...ss.sm,maxWidth:"140px"}}/><button onClick={add} disabled={!amt||!desc.trim()} style={{...ss.btn,background:amt&&desc.trim()?"#2E7D32":"#ccc",color:"#fff",fontSize:"12px",padding:"8px 14px"}}>+ Add</button></div>}
  </div>);
}

/* === DOCUMENTS === */
function DocumentsPanel({orderId,userRole}){const[docs,setDocs]=useState([]);const[ld,setLd]=useState(true);const[up,setUp]=useState(false);const[st,setSt]=useState("Invoice");const fr=useRef(null);const sb=createClient();
  const load=useCallback(async()=>{const{data}=await sb.from("order_documents").select("*").eq("order_id",orderId).order("uploaded_at",{ascending:false});setDocs(data||[]);setLd(false)},[orderId]);useEffect(()=>{load()},[load]);
  const upload=async(e)=>{const f=e.target.files?.[0];if(!f)return;if(f.size>10*1024*1024){alert("Max 10MB.");return}setUp(true);try{const ext=f.name.split(".").pop();const fp=`${orderId}/${Date.now()}.${ext}`;const{error:ue}=await sb.storage.from("order-documents").upload(fp,f,{contentType:f.type});if(ue)throw ue;await sb.from("order_documents").insert({order_id:orderId,name:f.name,doc_type:st,file_path:fp,file_size:f.size,mime_type:f.type});await logAct(sb,orderId,"document",`Uploaded ${st}: ${f.name}`);await load()}catch(err){alert("Failed: "+err.message)}setUp(false);if(fr.current)fr.current.value=""};
  const view=async(d)=>{const{data}=await sb.storage.from("order-documents").createSignedUrl(d.file_path,3600);if(data?.signedUrl)window.open(data.signedUrl,"_blank")};const dl=async(d)=>{const{data}=await sb.storage.from("order-documents").download(d.file_path);if(data){const u=URL.createObjectURL(data);const a=document.createElement("a");a.href=u;a.download=d.name;a.click();URL.revokeObjectURL(u)}};const rm=async(d)=>{await sb.storage.from("order-documents").remove([d.file_path]);await sb.from("order_documents").delete().eq("id",d.id);await logAct(sb,orderId,"document_deleted",`Removed: ${d.name}`);await load()};const fs=(b)=>!b?"":b<1024?b+"B":b<1048576?(b/1024).toFixed(0)+"KB":(b/1048576).toFixed(1)+"MB";const canUp=ROLES_CAN_UPLOAD.includes(userRole);
  return(<div style={{marginTop:"18px",padding:"16px",background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0"}}><div style={{...ss.label,marginBottom:"12px",color:"#666"}}>Documents</div>{ld?<div style={{fontSize:"12px",color:"#bbb"}}>Loading...</div>:docs.length>0?<div style={{display:"flex",flexDirection:"column",gap:"6px",marginBottom:"14px"}}>{docs.map(d=><div key={d.id} style={{display:"flex",alignItems:"center",gap:"8px",padding:"8px 10px",background:"#fff",borderRadius:"6px",border:"1px solid #e8e8e5",flexWrap:"wrap"}}><span style={{fontSize:"16px"}}>{DOC_ICONS[d.doc_type]||"*"}</span><div style={{flex:1,minWidth:"100px"}}><div style={{fontSize:"13px",fontWeight:600,color:"#333",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{d.name}</div><div style={{fontSize:"10px",color:"#999"}}>{d.doc_type} - {fs(d.file_size)} - {new Date(d.uploaded_at).toLocaleDateString("en-GB",{day:"numeric",month:"short"})}</div></div><div style={{display:"flex",gap:"4px"}}><button onClick={()=>view(d)} style={{padding:"4px 8px",borderRadius:"4px",border:"1px solid #ddd",background:"#fff",fontSize:"11px",fontWeight:600,color:"#1565C0",cursor:"pointer"}}>View</button><button onClick={()=>dl(d)} style={{padding:"4px 8px",borderRadius:"4px",border:"1px solid #ddd",background:"#fff",fontSize:"11px",fontWeight:600,color:"#2E7D32",cursor:"pointer"}}>DL</button>{userRole==="admin"&&<button onClick={()=>{if(confirm("Remove?"))rm(d)}} style={{padding:"4px 8px",borderRadius:"4px",border:"1px solid #f0d0d0",background:"#fff",fontSize:"11px",fontWeight:600,color:"#C62828",cursor:"pointer"}}>x</button>}</div></div>)}</div>:<div style={{fontSize:"12px",color:"#bbb",padding:"4px 0 12px",fontStyle:"italic"}}>No documents.</div>}
    {canUp&&<div style={{display:"flex",gap:"8px",alignItems:"center",flexWrap:"wrap"}}><select value={st} onChange={e=>setSt(e.target.value)} style={{padding:"8px 10px",borderRadius:"6px",border:"1.5px solid #e0e0e0",fontSize:"13px",background:"#fff"}}>{DOC_TYPES.map(t=><option key={t}>{t}</option>)}</select><label style={{display:"inline-flex",alignItems:"center",gap:"5px",padding:"8px 14px",borderRadius:"6px",border:"1.5px dashed #ccc",fontSize:"13px",fontWeight:600,color:"#666",cursor:"pointer",background:"#fff"}}>{up?"Uploading...":"Upload"}<input ref={fr} type="file" accept=".pdf,.png,.jpg,.jpeg,.doc,.docx,.xls,.xlsx" onChange={upload} style={{display:"none"}}/></label></div>}</div>);
}

/* === ACTIVITY === */
function ActivityTimeline({orderId}){const[a,setA]=useState([]);const[l,setL]=useState(false);const sb=createClient();useEffect(()=>{(async()=>{const{data}=await sb.from("order_activities").select("*").eq("order_id",orderId).order("created_at",{ascending:false}).limit(30);setA(data||[]);setL(true)})()},[orderId]);if(!l)return null;return(<div style={{marginTop:"18px",padding:"16px",background:"#FAFAF8",borderRadius:"10px",border:"1.5px solid #E8E5E0"}}><div style={{...ss.label,marginBottom:"12px",color:"#666"}}>Activity</div>{a.length===0?<div style={{fontSize:"12px",color:"#bbb",fontStyle:"italic"}}>No activity.</div>:<div style={{display:"flex",flexDirection:"column",gap:"2px",maxHeight:"200px",overflowY:"auto"}}>{a.map(x=><div key={x.id} style={{fontSize:"12px",color:"#666",padding:"5px 0",borderBottom:"1px solid #f0f0f0",display:"flex",gap:"8px"}}><span style={{color:"#bbb",fontSize:"11px",minWidth:"65px",flexShrink:0}}>{new Date(x.created_at).toLocaleDateString("en-GB",{day:"numeric",month:"short"})}</span><span>{x.description}</span></div>)}</div>}</div>)}

