function QuotePrompt({onConfirm,onCancel}){const[n,setN]=useState("");return(<div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}><div style={{background:"#fff",borderRadius:"12px",padding:"24px",maxWidth:"400px",width:"100%",boxShadow:"0 8px 40px rgba(0,0,0,0.2)"}}><h3 style={{fontSize:"16px",fontWeight:700,marginBottom:"16px"}}>Enter Quote Number</h3><input type="text" value={n} onChange={e=>setN(e.target.value)} placeholder="e.g. QT-001234" style={ss.input} autoFocus/><div style={{display:"flex",gap:"10px",marginTop:"18px"}}><button onClick={()=>onConfirm(n.trim())} style={{...ss.btn,background:"#1565C0",color:"#fff",flex:1}}>Save</button><button onClick={()=>onConfirm("")} style={{...ss.btn,background:"#f5f5f5",color:"#999"}}>Skip</button><button onClick={onCancel} style={{...ss.btn,background:"#f5f5f5",color:"#666"}}>Cancel</button></div></div></div>)}
function DepositPrompt({onConfirm,onCancel}){const[amt,setAmt]=useState("");const[desc,setDesc]=useState("Deposit");const[dt,setDt]=useState(new Date().toISOString().split("T")[0]);const[inv,setInv]=useState("");const v=parseFloat(amt)>0&&desc.trim();return(<div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}><div style={{background:"#fff",borderRadius:"12px",padding:"24px",maxWidth:"420px",width:"100%",boxShadow:"0 8px 40px rgba(0,0,0,0.2)"}}><h3 style={{fontSize:"16px",fontWeight:700,marginBottom:"16px"}}>Record Deposit and Invoice</h3><div style={{display:"flex",flexDirection:"column",gap:"10px"}}><div><label style={ss.label}>Invoice Number</label><input type="text" value={inv} onChange={e=>setInv(e.target.value)} placeholder="INV-001234" style={ss.input}/></div><div><label style={ss.label}>Amount (KES) *</label><input type="number" value={amt} onChange={e=>setAmt(e.target.value)} style={ss.input} autoFocus/></div><div><label style={ss.label}>Description *</label><input type="text" value={desc} onChange={e=>setDesc(e.target.value)} style={ss.input}/></div><div><label style={ss.label}>Date</label><input type="date" value={dt} onChange={e=>setDt(e.target.value)} style={ss.input}/></div></div><div style={{display:"flex",gap:"10px",marginTop:"18px"}}><button onClick={()=>v&&onConfirm({amount:parseFloat(amt),description:desc.trim(),payment_date:dt,invoice_number:inv.trim()})} disabled={!v} style={{...ss.btn,background:v?"#2E7D32":"#ccc",color:"#fff",flex:1}}>Record</button><button onClick={onCancel} style={{...ss.btn,background:"#f5f5f5",color:"#666"}}>Cancel</button></div></div></div>)}
function RepairForm({parentOrder,onConfirm,onCancel}){const[reason,setReason]=useState(REPAIR_REASONS[0]);const[type,setType]=useState("repair");const[desc,setDesc]=useState("");const[val,setVal]=useState("");return(<div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}><div style={{background:"#fff",borderRadius:"12px",padding:"24px",maxWidth:"460px",width:"100%",boxShadow:"0 8px 40px rgba(0,0,0,0.2)",maxHeight:"90vh",overflowY:"auto"}}><h3 style={{fontSize:"16px",fontWeight:700,marginBottom:"16px"}}>Create Return / Repair</h3><div style={{display:"flex",flexDirection:"column",gap:"10px"}}><div><label style={ss.label}>Type</label><select value={type} onChange={e=>setType(e.target.value)} style={ss.input}><option value="repair">Repair</option><option value="return">Return</option></select></div><div><label style={ss.label}>Reason</label><select value={reason} onChange={e=>setReason(e.target.value)} style={ss.input}>{REPAIR_REASONS.map(r=><option key={r}>{r}</option>)}</select></div><div><label style={ss.label}>Description *</label><textarea value={desc} onChange={e=>setDesc(e.target.value)} rows={3} style={{...ss.input,resize:"vertical"}} placeholder="What needs repair"/></div><div><label style={ss.label}>Cost (KES)</label><input type="number" value={val} onChange={e=>setVal(e.target.value)} style={ss.input}/></div></div><div style={{display:"flex",gap:"10px",marginTop:"18px"}}><button onClick={()=>desc.trim()&&onConfirm({type,reason,description:desc.trim(),value:parseFloat(val)||0})} disabled={!desc.trim()} style={{...ss.btn,background:desc.trim()?"#C62828":"#ccc",color:"#fff",flex:1}}>Create</button><button onClick={onCancel} style={{...ss.btn,background:"#f5f5f5",color:"#666"}}>Cancel</button></div></div></div>)}

/* === ORDER FORM === */
function OrderForm({onSave,onCancel,initial,userRole}){
  const FIELDS=["client","contact_person","author","items","due_date","assigned_to","notes","total_value","quote_number","invoice_number","customer_type","payment_terms","batch_delivery"];
  const defaults={client:"",contact_person:"",author:"",items:"",due_date:"",assigned_to:"",notes:"",total_value:"",quote_number:"",invoice_number:"",customer_type:"retail",payment_terms:"cash_before",batch_delivery:false};
  const initV=initial?FIELDS.reduce((a,k)=>{a[k]=initial[k]??"";return a},{}):defaults;
  const[form,setForm]=useState(initV);const[orderItems,setOrderItems]=useState([]);const[ldItems,setLdItems]=useState(false);const sb=createClient();
  const set=(k)=>(e)=>setForm({...form,[k]:e.target.value});const valid=form.client.trim()&&(orderItems.length>0||form.items?.trim());
  useEffect(()=>{if(initial?.id){(async()=>{const{data}=await sb.from("order_items").select("*").eq("order_id",initial.id).order("sort_order");if(data)setOrderItems(data.map(d=>({...d,_id:d.id})));setLdItems(true)})()}else setLdItems(true)},[initial]);
  return(<div style={{background:"#fff",borderRadius:"10px",padding:"20px",border:"1px solid #e0e0e0",marginBottom:"20px",boxShadow:"0 2px 12px rgba(0,0,0,0.06)"}}>
    <h3 style={{margin:"0 0 16px",fontSize:"16px",fontWeight:700}}>{initial?"Edit Order":"New Order"}</h3>
    <div className="form-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px"}}>
      {[{l:"Client Name *",k:"client",t:"text"},{l:"Client Contact",k:"contact_person",t:"text",p:"Name / phone / email"},{l:"Order Author",k:"author",t:"text",p:"Who owns this?"},{l:"Assigned To",k:"assigned_to",t:"text",p:"Workshop / person"},{l:"Due Date",k:"due_date",t:"date"},{l:"Order Value (KES)",k:"total_value",t:"number",p:"e.g. 150000"},{l:"Quote Number",k:"quote_number",t:"text",p:"From Manager.io"},{l:"Invoice Number",k:"invoice_number",t:"text",p:"From Manager.io"}].map(({l,k,t,p})=><div key={k}><label style={ss.label}>{l}</label><input type={t} value={form[k]||""} onChange={set(k)} placeholder={p} style={ss.input}/></div>)}
      <div><label style={ss.label}>Customer Type</label><select value={form.customer_type||"retail"} onChange={set("customer_type")} style={ss.input}>{CUSTOMER_TYPES.map(c=><option key={c.id} value={c.id}>{c.label}</option>)}</select></div>
      <div><label style={ss.label}>Payment Terms</label><select value={form.payment_terms||"cash_before"} onChange={set("payment_terms")} style={ss.input}>{PAYMENT_TERMS.map(p=><option key={p.id} value={p.id}>{p.label}</option>)}</select></div>
      {["admin","production_manager"].includes(userRole)&&<div><label style={ss.label}>Batch Delivery</label><div style={{display:"flex",alignItems:"center",gap:"8px"}}><button type="button" onClick={()=>setForm({...form,batch_delivery:!form.batch_delivery})} style={{padding:"6px 14px",borderRadius:"6px",border:"1.5px solid "+(form.batch_delivery?"#2E7D32":"#e0e0e0"),background:form.batch_delivery?"#E8F5E9":"#fff",color:form.batch_delivery?"#2E7D32":"#999",fontSize:"12px",fontWeight:600,cursor:"pointer"}}>{form.batch_delivery?"Enabled":"Disabled"}</button><span style={{fontSize:"11px",color:"#bbb"}}>For large/phased deliveries</span></div></div>}
    </div>
    <div style={{marginTop:"14px"}}>{ldItems&&<ItemsBuilder items={orderItems} onChange={setOrderItems}/>}</div>
    <div style={{marginTop:"14px"}}><label style={ss.label}>Additional Notes</label><textarea value={form.notes||""} onChange={set("notes")} rows={2} style={{...ss.input,resize:"vertical"}} placeholder="Special instructions, delivery address"/></div>
    <div style={{display:"flex",gap:"10px",marginTop:"16px"}}><button onClick={()=>valid&&onSave(form,orderItems)} disabled={!valid} style={{...ss.btn,background:valid?"#1a1a1a":"#ccc",color:"#fff"}}>{initial?"Update":"Add Order"}</button><button onClick={onCancel} style={{...ss.btn,background:"#f5f5f5",color:"#666"}}>Cancel</button></div>
  </div>);
}

/* ================================================ */
/* ============= MAIN ORDER TRACKER =============== */
/* ================================================ */
export default function OrderTracker(){
  const[orders,setOrders]=useState([]);const[loaded,setLoaded]=useState(false);const[showForm,setShowForm]=useState(false);const[editId,setEditId]=useState(null);
  const[filterStatus,setFilterStatus]=useState("All");const[filterType,setFilterType]=useState("All");const[search,setSearch]=useState("");
  const[expandedId,setExpandedId]=useState(null);const[itemSums,setItemSums]=useState({});const[docCounts,setDocCounts]=useState({});const[payTotals,setPayTotals]=useState({});const[delTotals,setDelTotals]=useState({});
  const[expItems,setExpItems]=useState([]);const[expTotalQty,setExpTotalQty]=useState(0);
  const[depositPrompt,setDepositPrompt]=useState(null);const[quotePrompt,setQuotePrompt]=useState(null);const[repairForm,setRepairForm]=useState(null);const[batchPrompt,setBatchPrompt]=useState(null);
  const[userRole,setUserRole]=useState("viewer");const[userName,setUserName]=useState("");const[adminSettings,setAdminSettings]=useState({});
  const sb=createClient();

  useEffect(()=>{(async()=>{const{data:{user}}=await sb.auth.getUser();if(user){const{data:p}=await sb.from("user_profiles").select("role,display_name").eq("id",user.id).single();if(p){setUserRole(p.role);setUserName(p.display_name||user.email?.split("@")[0]||"")}}const{data:sets}=await sb.from("admin_settings").select("*");if(sets){const s={};sets.forEach(r=>{s[r.key]=r.value});setAdminSettings(s)}})()},[]);

  const loadOrders=useCallback(async()=>{
    const{data:ord}=await sb.from("orders").select("*").order("created_at",{ascending:false});if(ord)setOrders(ord);
    const{data:items}=await sb.from("order_items").select("order_id,category,quantity");if(items){const m={};items.forEach(i=>{if(!m[i.order_id])m[i.order_id]={qty:0,cats:{}};m[i.order_id].qty+=(i.quantity||1);m[i.order_id].cats[i.category]=(m[i.order_id].cats[i.category]||0)+(i.quantity||1)});setItemSums(m)}
    const{data:docs}=await sb.from("order_documents").select("order_id");if(docs){const c={};docs.forEach(d=>{c[d.order_id]=(c[d.order_id]||0)+1});setDocCounts(c)}
    const{data:pays}=await sb.from("order_payments").select("order_id,amount");if(pays){const t={};pays.forEach(p=>{t[p.order_id]=(t[p.order_id]||0)+parseFloat(p.amount)});setPayTotals(t)}
    const{data:dels}=await sb.from("order_deliveries").select("order_id,quantity");if(dels){const t={};dels.forEach(d=>{t[d.order_id]=(t[d.order_id]||0)+(d.quantity||0)});setDelTotals(t)}
    setLoaded(true);
  },[]);
  useEffect(()=>{loadOrders()},[loadOrders]);
  const loadExpanded=useCallback(async(oid)=>{const{data:items}=await sb.from("order_items").select("*").eq("order_id",oid).order("sort_order");setExpItems(items||[]);setExpTotalQty((items||[]).reduce((s,i)=>s+(i.quantity||1),0))},[]);
  useEffect(()=>{setExpItems([]);setExpTotalQty(0);if(expandedId)loadExpanded(expandedId)},[expandedId,loadExpanded]);

  const saveItems=async(oid,items)=>{await sb.from("order_items").delete().eq("order_id",oid);if(items.length>0){const rows=items.map((i,idx)=>({order_id:oid,category:i.category,description:i.description||null,quantity:parseInt(i.quantity)||1,size:i.size||null,finish_type:i.finish_type||null,finish_color:i.finish_color||null,wood_type:i.wood_type||null,unit_price:parseFloat(i.unit_price)||0,notes:i.notes||null,sort_order:idx}));await sb.from("order_items").insert(rows)}};

  const addOrder=async(form,items)=>{
    const summary=items.length>0?items.map(i=>`${i.quantity}x ${i.category}${i.size?" - "+i.size:""}`).join("\n"):form.items||"";
    const payload={...form,due_date:form.due_date||null,total_value:parseFloat(form.total_value)||0,status:"Inquiry",items:summary,quote_number:form.quote_number||null,invoice_number:form.invoice_number||null,customer_type:form.customer_type||"retail",payment_terms:form.payment_terms||"cash_before",batch_delivery:form.batch_delivery||false};
    delete payload.order_num;
    const{data:created,error}=await sb.from("orders").insert(payload).select().single();
    if(error){alert("Error: "+error.message);return}
    if(created){await saveItems(created.id,items);await logAct(sb,created.id,"created",`Order ${created.order_num} created for ${form.client}`)}
    await loadOrders();setShowForm(false);
    if(created&&!payload.batch_delivery){const tq=items.reduce((s,i)=>s+(parseInt(i.quantity)||1),0);const ut=parseInt(adminSettings.batch_delivery_unit_threshold)||20;const vt=parseInt(adminSettings.batch_delivery_value_threshold)||500000;if(tq>ut||(parseFloat(payload.total_value)||0)>vt){setBatchPrompt(created.id)}}
  };

  const updateOrder=async(form,items)=>{
    const old=orders.find(o=>o.id===editId);const summary=items.length>0?items.map(i=>`${i.quantity}x ${i.category}${i.size?" - "+i.size:""}`).join("\n"):form.items||old?.items||"";
    const payload={...form,due_date:form.due_date||null,total_value:parseFloat(form.total_value)||0,items:summary,quote_number:form.quote_number||null,invoice_number:form.invoice_number||null,customer_type:form.customer_type||"retail",payment_terms:form.payment_terms||"cash_before",batch_delivery:form.batch_delivery||false};
    delete payload.status;const{error}=await sb.from("orders").update(payload).eq("id",editId);if(error){alert("Error: "+error.message);return}
    await saveItems(editId,items);await logAct(sb,editId,"edited","Order updated");await loadOrders();setEditId(null);
  };

  const advanceStatus=async(id,oldSt,newSt)=>{
    const order=orders.find(o=>o.id===id);const tp=payTotals[id]||0;const tv=parseFloat(order?.total_value)||0;
    const totalQty=itemSums[id]?.qty||order?.deliverable_units||0;const totalDel=delTotals[id]||0;
    const sList=getStatusList(order?.order_type);
    if(userRole==="sales"&&sList.indexOf(newSt)>sList.indexOf(SALES_MAX_ADVANCE_TO)){alert("Sales users can only advance orders up to Deposit Paid.");return}
    if(newSt==="Quote Approved"&&!order.quote_number){setQuotePrompt({orderId:id,oldStatus:oldSt});return}
    if(newSt==="Deposit Paid"&&tp<=0){setDepositPrompt({orderId:id,oldStatus:oldSt});return}
    if(newSt==="Delivered"&&order?.batch_delivery&&totalQty>0&&totalDel<totalQty){alert(`Delivery not complete.\nDelivered: ${totalDel} of ${totalQty}\nRemaining: ${totalQty-totalDel}`);return}
    if(newSt==="Closed"){if(order?.batch_delivery&&totalQty>0&&totalDel<totalQty){alert(`Cannot close. Delivery: ${totalDel}/${totalQty}`);return}if(tv>0&&tp<tv){alert(`Cannot close. Balance: KES ${(tv-tp).toLocaleString()}`);return}}
    await sb.from("orders").update({status:newSt}).eq("id",id);await logAct(sb,id,"status_change",`Status: ${oldSt} -> ${newSt}`,oldSt,newSt);
    setOrders(p=>p.map(o=>o.id===id?{...o,status:newSt}:o));
  };

  const handleQuoteConfirm=async(q)=>{const{orderId,oldStatus}=quotePrompt;if(q)await sb.from("orders").update({quote_number:q}).eq("id",orderId);await sb.from("orders").update({status:"Quote Approved"}).eq("id",orderId);await logAct(sb,orderId,"status_change",`${oldStatus} -> Quote Approved${q?" (Q: "+q+")":""}`,oldStatus,"Quote Approved");setQuotePrompt(null);await loadOrders()};
  const handleDepositConfirm=async(d)=>{const{orderId,oldStatus}=depositPrompt;if(d.invoice_number)await sb.from("orders").update({invoice_number:d.invoice_number}).eq("id",orderId);await sb.from("order_payments").insert({order_id:orderId,amount:d.amount,description:d.description,payment_date:d.payment_date});await logAct(sb,orderId,"payment",`Deposit: KES ${d.amount.toLocaleString()}`);await sb.from("orders").update({status:"Deposit Paid"}).eq("id",orderId);await logAct(sb,orderId,"status_change",`${oldStatus} -> Deposit Paid`,oldStatus,"Deposit Paid");setDepositPrompt(null);await loadOrders()};
  const handleRepairConfirm=async(d)=>{const p=repairForm;const payload={client:p.client,contact_person:p.contact_person,author:p.author,items:d.description,status:"Reported",order_type:d.type,parent_order_id:p.id,repair_reason:d.reason,total_value:d.value,assigned_to:p.assigned_to,notes:`${d.type.toUpperCase()} for ${p.order_num}`,quote_number:p.quote_number,invoice_number:p.invoice_number};const{data:created,error}=await sb.from("orders").insert(payload).select().single();if(error){alert("Error: "+error.message);setRepairForm(null);return}if(created){await logAct(sb,created.id,"created",`${d.type} created - ${d.reason}`);await logAct(sb,p.id,"repair_created",`${d.type} ${created.order_num} created`)}setRepairForm(null);await loadOrders()};
  const deleteOrder=async(id)=>{if(userRole!=="admin"){alert("Only admins can delete.");return}const{data:docs}=await sb.from("order_documents").select("file_path").eq("order_id",id);if(docs?.length)await sb.storage.from("order-documents").remove(docs.map(d=>d.file_path));await sb.from("orders").delete().eq("id",id);await loadOrders();setExpandedId(null)};

  const filtered=orders.filter(o=>{if(filterStatus!=="All"&&o.status!==filterStatus)return false;if(filterType==="standard"&&(o.order_type==="repair"||o.order_type==="return"))return false;if(filterType==="repairs"&&o.order_type!=="repair"&&o.order_type!=="return")return false;if(search){const q=search.toLowerCase();return[o.client,o.items,o.order_num,o.assigned_to,o.author,o.contact_person,o.notes,o.quote_number,o.invoice_number].filter(Boolean).join(" ").toLowerCase().includes(q)}return true});
  const allSt=[...new Set([...STATUSES,...REPAIR_STATUSES])];const stCounts=allSt.reduce((a,s)=>{a[s]=orders.filter(o=>o.status===s).length;return a},{});
  const canCreate=ROLES_CAN_CREATE.includes(userRole);const canEdit=ROLES_CAN_EDIT.includes(userRole);const canAdvance=ROLES_CAN_ADVANCE.includes(userRole);

  if(!loaded)return <div style={{padding:"40px",textAlign:"center",color:"#aaa"}}>Loading...</div>;

  return(<div>
    {quotePrompt&&<QuotePrompt onConfirm={handleQuoteConfirm} onCancel={()=>setQuotePrompt(null)}/>}
    {depositPrompt&&<DepositPrompt onConfirm={handleDepositConfirm} onCancel={()=>setDepositPrompt(null)}/>}
    {repairForm&&<RepairForm parentOrder={repairForm} onConfirm={handleRepairConfirm} onCancel={()=>setRepairForm(null)}/>}
    {batchPrompt&&<div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"16px"}}><div style={{background:"#fff",borderRadius:"12px",padding:"24px",maxWidth:"400px",width:"100%",boxShadow:"0 8px 40px rgba(0,0,0,0.2)"}}><h3 style={{fontSize:"16px",fontWeight:700,marginBottom:"16px"}}>Enable Batch Delivery?</h3><p style={{fontSize:"12px",color:"#888",marginBottom:"16px"}}>This order exceeds the threshold. Enable batch delivery for hotel, bulk, or multi-phase projects.</p><div style={{display:"flex",gap:"10px"}}><button onClick={async()=>{await sb.from("orders").update({batch_delivery:true}).eq("id",batchPrompt);await loadOrders();setBatchPrompt(null)}} style={{...ss.btn,background:"#2E7D32",color:"#fff",flex:1}}>Yes, Enable</button><button onClick={()=>setBatchPrompt(null)} style={{...ss.btn,background:"#f5f5f5",color:"#666",flex:1}}>No</button></div></div></div>}

    <div style={{padding:"20px 16px",display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:"10px"}}><div><div style={{fontSize:"24px",fontWeight:800,letterSpacing:"-0.5px"}}>Orders</div><div style={{fontSize:"12px",color:"#999"}}>{orders.length} total - {orders.filter(o=>!["Delivered","Closed","Redelivered"].includes(o.status)).length} active</div></div>{canCreate&&<button onClick={()=>{setShowForm(true);setEditId(null)}} style={{...ss.btn,background:"#E8512A",color:"#fff",padding:"11px 24px",fontWeight:700,borderRadius:"8px",fontSize:"14px",boxShadow:"0 2px 8px rgba(232,81,42,0.3)"}}>+ New Order</button>}</div>

    <div style={{display:"flex",gap:"6px",padding:"0 16px 12px",overflowX:"auto",WebkitOverflowScrolling:"touch"}}>{allSt.filter(s=>stCounts[s]>0||STATUSES.includes(s)).map(s=><div key={s} onClick={()=>setFilterStatus(filterStatus===s?"All":s)} style={{padding:"5px 10px",borderRadius:"6px",cursor:"pointer",flexShrink:0,background:filterStatus===s?(ALL_STATUS_COLORS[s]?.bg||"#eee"):"#fff",border:`1.5px solid ${filterStatus===s?(ALL_STATUS_COLORS[s]?.border||"#ccc"):"#e0e0e0"}`,fontSize:"11px",whiteSpace:"nowrap"}}><span style={{fontWeight:700,color:ALL_STATUS_COLORS[s]?.text||"#333",fontFamily:"'DM Mono',monospace"}}>{stCounts[s]||0}</span><span style={{color:"#888",marginLeft:"4px"}}>{s}</span></div>)}</div>

    <div style={{padding:"0 16px 20px"}}>
      <div style={{display:"flex",gap:"8px",marginBottom:"14px",flexWrap:"wrap"}}><input type="text" placeholder="Search client, quote, invoice..." value={search} onChange={e=>setSearch(e.target.value)} style={{...ss.input,flex:1,minWidth:"180px",maxWidth:"320px",background:"#fff"}}/><select value={filterType} onChange={e=>setFilterType(e.target.value)} style={{...ss.input,maxWidth:"150px",background:"#fff"}}><option value="All">All Types</option><option value="standard">Orders</option><option value="repairs">Repairs</option></select>{(filterStatus!=="All"||filterType!=="All"||search)&&<button onClick={()=>{setFilterStatus("All");setFilterType("All");setSearch("")}} style={{...ss.btn,background:"#fff",color:"#999",border:"1.5px solid #e0e0e0",fontSize:"12px",padding:"8px 12px"}}>Clear</button>}</div>

      {showForm&&canCreate&&<OrderForm onSave={addOrder} onCancel={()=>setShowForm(false)} userRole={userRole}/>}
      {editId&&canEdit&&<OrderForm initial={orders.find(o=>o.id===editId)} onSave={updateOrder} onCancel={()=>setEditId(null)} userRole={userRole}/>}

      {filtered.length===0?<div style={{textAlign:"center",padding:"60px 20px",color:"#bbb",background:"#fff",borderRadius:"10px",border:"1px solid #e8e8e5"}}><div style={{fontSize:"36px",marginBottom:"10px"}}>O</div><div style={{fontSize:"14px",fontWeight:600,color:"#999"}}>{orders.length===0?"No orders yet":"No match"}</div></div>:(
        <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
          {filtered.map(order=>{
            const expanded=expandedId===order.id;const days=order.due_date?Math.ceil((new Date(order.due_date+"T12:00:00")-new Date())/86400000):null;
            const overdue=days!==null&&days<0&&!["Delivered","Closed","Redelivered"].includes(order.status);
            const tp=payTotals[order.id]||0;const tv=parseFloat(order.total_value)||0;const ps=getPayStatus(tp,tv);const pct=tv>0?Math.round((tp/tv)*100):0;const bal=tv-tp;
            const iS=itemSums[order.id];const totalQty=iS?.qty||order.deliverable_units||0;const totalDel=delTotals[order.id]||0;const delPct=totalQty>0?Math.round((totalDel/totalQty)*100):0;
            const sList=getStatusList(order.order_type);const cIdx=sList.indexOf(order.status);const nextSt=cIdx<sList.length-1?sList[cIdx+1]:null;
            const isRepair=order.order_type==="repair"||order.order_type==="return";
            const showDelivery=DELIVERY_VISIBLE_FROM.includes(order.status)&&!isRepair&&order.batch_delivery;
            const children=orders.filter(o=>o.parent_order_id===order.id);const parentOrd=order.parent_order_id?orders.find(o=>o.id===order.parent_order_id):null;

            const borderClass=STATUS_BORDER_CLASS[order.status]||"";return(<div key={order.id} className={`order-card ${borderClass}`} style={{background:"#fff",borderRadius:"10px",border:`1.5px solid ${overdue?"#ef9a9a":"#e0ddd8"}`,overflow:"hidden",boxShadow:expanded?"var(--shadow-lg)":"var(--shadow-sm)"}}>
              <div onClick={()=>setExpandedId(expanded?null:order.id)} style={{padding:"12px 16px",cursor:"pointer"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"6px",flexWrap:"wrap",gap:"4px"}}>
                  <div style={{display:"flex",gap:"6px",alignItems:"center",flexWrap:"wrap"}}><span style={{fontSize:"12px",fontFamily:"'DM Mono',monospace",color:"#888",fontWeight:500,background:"#f0ede8",padding:"2px 6px",borderRadius:"4px"}}>{order.order_num}</span>{isRepair&&<span style={{fontSize:"9px",fontWeight:700,color:"#C62828",background:"#FCE4EC",padding:"2px 6px",borderRadius:"3px",textTransform:"uppercase"}}>{order.order_type}</span>}{order.customer_type&&order.customer_type!=="retail"&&<span style={{fontSize:"9px",fontWeight:700,color:order.customer_type==="reseller"?"#7B1FA2":"#1565C0",background:order.customer_type==="reseller"?"#F3E5F5":"#E3F2FD",padding:"2px 6px",borderRadius:"3px",textTransform:"uppercase"}}>{order.customer_type}</span>}{order.quote_number&&<span style={{fontSize:"10px",color:"#1565C0",background:"#E3F2FD",padding:"1px 5px",borderRadius:"3px"}}>Q:{order.quote_number}</span>}{order.invoice_number&&<span style={{fontSize:"10px",color:"#512DA8",background:"#EDE7F6",padding:"1px 5px",borderRadius:"3px"}}>I:{order.invoice_number}</span>}</div>
                  <div style={{display:"flex",gap:"4px",alignItems:"center",flexWrap:"wrap"}}><Badge status={order.status}/>{tv>0&&<Badge status={ps} type="payment"/>}</div>
                </div>
                <div style={{fontSize:"16px",fontWeight:700,color:overdue?"#DC2626":"#111",marginBottom:"4px",letterSpacing:"-0.3px"}}>{order.client}{docCounts[order.id]&&<span style={{fontSize:"10px",color:"#2E7D32",marginLeft:"6px"}}>{docCounts[order.id]} docs</span>}{children.length>0&&<span style={{fontSize:"10px",color:"#E65100",marginLeft:"6px"}}>{children.length} repairs</span>}</div>
                {iS?<div style={{fontSize:"12px",color:"#666",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{Object.entries(iS.cats).map(([c,q])=>`${q}x ${c}`).join(" - ")}</div>:<div style={{fontSize:"12px",color:"#999",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{order.items}</div>}
                {order.notes&&<div style={{fontSize:"11px",color:"#E65100",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",marginTop:"2px"}}>! {order.notes}</div>}
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:"6px",fontSize:"11px",marginTop:"4px"}}><div style={{display:"flex",gap:"12px",color:"#888"}}>{tv>0&&<span><strong style={{color:"#333"}}>{pct}%</strong> paid - Bal: KES {Math.max(bal,0).toLocaleString()}</span>}{showDelivery&&totalQty>0&&<span>{delPct}% delivered ({totalDel}/{totalQty})</span>}{order.author&&<span>by {order.author}</span>}</div><div style={{color:overdue?"#C62828":"#999",fontWeight:overdue?700:400}}>{order.due_date?<>{new Date(order.due_date+"T12:00:00").toLocaleDateString("en-GB",{day:"numeric",month:"short"})}{overdue&&` - ${Math.abs(days)}d late`}</>:""}</div></div>
              </div>

              {expanded&&(<div style={{padding:"0 16px 16px",borderTop:"1px solid #f0f0f0"}}>
                <div className="detail-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",marginTop:"14px"}}>{[{l:"Author",v:order.author},{l:"Client Contact",v:order.contact_person},{l:"Assigned To",v:order.assigned_to},{l:"Created",v:new Date(order.created_at).toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})},{l:"Order Value",v:tv?`KES ${tv.toLocaleString()}`:"Not set"},{l:"Due Date",v:order.due_date?new Date(order.due_date+"T12:00:00").toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"}):"Not set"},{l:"Quote #",v:order.quote_number},{l:"Invoice #",v:order.invoice_number},{l:"Customer Type",v:CUSTOMER_TYPES.find(c=>c.id===order.customer_type)?.label||"Retail"},{l:"Payment Terms",v:PAYMENT_TERMS.find(p=>p.id===order.payment_terms)?.label||"-"},{l:"Batch Delivery",v:order.batch_delivery?"Enabled":"Standard"}].map(({l,v})=><div key={l}><div style={ss.label}>{l}</div><div style={{fontSize:"13px",color:"#333",marginTop:"2px"}}>{v||"-"}</div></div>)}{isRepair&&<div><div style={ss.label}>Repair Reason</div><div style={{fontSize:"13px",color:"#C62828",marginTop:"2px",fontWeight:600}}>{order.repair_reason||"-"}</div></div>}</div>

                {(parentOrd||children.length>0)&&<div style={{marginTop:"14px",padding:"12px",background:"#FFF8E1",borderRadius:"8px",border:"1px solid #FFD54F"}}><div style={{...ss.label,color:"#F57F17",marginBottom:"6px"}}>Linked Orders</div>{parentOrd&&<div style={{fontSize:"12px",color:"#333"}}>Original: <strong>{parentOrd.order_num}</strong> - {parentOrd.client}</div>}{children.map(c=><div key={c.id} style={{fontSize:"12px",color:"#333",padding:"2px 0"}}><span style={{fontSize:"10px",fontWeight:700,color:"#C62828",background:"#FCE4EC",padding:"1px 5px",borderRadius:"3px",textTransform:"uppercase",marginRight:"4px"}}>{c.order_type}</span><strong>{c.order_num}</strong> - {c.repair_reason} <Badge status={c.status}/></div>)}</div>}

                <ItemsTable items={expItems}/>
                {order.items&&!expItems.length&&<div style={{marginTop:"14px"}}><div style={ss.label}>Items</div><TruncText text={order.items} lines={3}/></div>}
                {order.notes&&<div style={{marginTop:"12px"}}><div style={ss.label}>Special Requests</div><TruncText text={order.notes} lines={3}/></div>}

                <div style={{marginTop:"16px"}}><div style={ss.label}>Workflow{isRepair?" (Repair)":""}</div>
                  <div style={{display:"flex",gap:"2px",marginTop:"6px",marginBottom:"10px"}}>{sList.map((s,i)=><div key={s} style={{flex:1,height:"6px",borderRadius:"3px",background:i<=cIdx?(ALL_STATUS_COLORS[s]?.text||"#333"):"#e8e8e5"}} title={s}/>)}</div>
                  <div style={{display:"flex",alignItems:"center",gap:"8px",flexWrap:"wrap"}}><Badge status={order.status}/>{canAdvance&&nextSt&&order.status!=="Closed"&&!(userRole==="sales"&&sList.indexOf(nextSt)>sList.indexOf(SALES_MAX_ADVANCE_TO))?<button onClick={()=>advanceStatus(order.id,order.status,nextSt)} style={{...ss.btn,background:"#1a1a1a",color:"#fff",fontSize:"12px",padding:"7px 14px"}}>Next: {nextSt}</button>:!nextSt&&<span style={{fontSize:"12px",color:"#2E7D32",fontWeight:600}}>Complete</span>}</div>
                </div>

                {showDelivery&&<DeliveryPanel orderId={order.id} totalQty={expTotalQty||order.deliverable_units||0} userRole={userRole} payBalance={Math.max(bal,0)} onDeliveryChange={(d)=>setDelTotals(p=>({...p,[order.id]:d}))} orderStatus={order.status} onAutoAdvance={async(newSt)=>{await sb.from("orders").update({status:newSt}).eq("id",order.id);await logAct(sb,order.id,"status_change",`${order.status} -> ${newSt} (auto)`,order.status,newSt);setOrders(p=>p.map(o=>o.id===order.id?{...o,status:newSt}:o))}}/>}
                <PaymentPanel orderId={order.id} totalValue={tv} userRole={userRole} orderStatus={order.status} onPaymentChange={(t)=>setPayTotals(p=>({...p,[order.id]:t}))}/>
                <DocumentsPanel orderId={order.id} userRole={userRole}/>
                <NotesThread orderId={order.id} userRole={userRole} userName={userName} orderStatus={order.status}/>
                <ActivityTimeline orderId={order.id}/>

                <div style={{display:"flex",gap:"8px",marginTop:"16px",flexWrap:"wrap"}}>
                  {order.status==="Closed"&&<div style={{padding:"10px 14px",background:"#F5F5F5",borderRadius:"6px",fontSize:"12px",color:"#999",fontWeight:600,textAlign:"center",width:"100%"}}>Order Archived - Read Only</div>}
                  {order.status!=="Closed"&&canEdit&&<button onClick={e=>{e.stopPropagation();setEditId(order.id);setExpandedId(null)}} style={{...ss.btn,background:"#f5f5f5",color:"#333",fontSize:"12px",padding:"8px 16px"}}>Edit</button>}
                  {order.status==="Delivered"&&!isRepair&&ROLES_CAN_REPAIR.includes(userRole)&&<button onClick={e=>{e.stopPropagation();setRepairForm(order)}} style={{...ss.btn,background:"#FFF3E0",color:"#E65100",border:"1px solid #FFB74D",fontSize:"12px",padding:"8px 16px"}}>Return / Repair</button>}
                  {order.status!=="Closed"&&userRole==="admin"&&<button onClick={e=>{e.stopPropagation();if(confirm("Delete permanently?"))deleteOrder(order.id)}} style={{...ss.btn,background:"#fff",color:"#C62828",border:"1px solid #ef9a9a",fontSize:"12px",padding:"8px 16px"}}>Delete</button>}
                </div>
              </div>)}
            </div>);
          })}
        </div>
      )}
    </div>
    <style>{`
@media(max-width:640px){.form-grid,.detail-grid{grid-template-columns:1fr!important}.items-table{display:none!important}.items-cards{display:flex!important}}
@media(min-width:641px){.items-cards{display:none!important}}
    `}</style>
  </div>);
}
